<?php
if (session_status() === PHP_SESSION_NONE) { session_start(); }
date_default_timezone_set((string)($_SESSION['timezone'] ?? 'Asia/Kolkata'));

foreach ([__DIR__.'/config/config.php', __DIR__.'/config.php', __DIR__.'/super-admin/includes/config.php'] as $f) {
    if (is_file($f)) { require_once $f; break; }
}
if (!isset($conn) || !($conn instanceof mysqli)) { die('Database configuration is not available.'); }
$conn->set_charset('utf8mb4');
if (empty($_SESSION['user_id'])) { header('Location: login.php'); exit; }

if (!function_exists('e')) { function e($v){ return htmlspecialchars((string)($v ?? ''), ENT_QUOTES, 'UTF-8'); } }

function rolePagePermission(mysqli $conn, $action) {
    if (($_SESSION['user_type'] ?? '') === 'Platform Admin') { return true; }
    $map = ['open'=>'can_open','value'=>'can_view_value','view'=>'can_view','create'=>'can_create','update'=>'can_update','approve'=>'can_approve','delete'=>'can_delete'];
    $field = $map[$action] ?? '';
    if ($field === '') return false;
    foreach (['perm.staff.roles','perm.staff'] as $key) {
        if (isset($_SESSION['permissions'][$key][$field])) return (int)$_SESSION['permissions'][$key][$field] === 1;
    }
    $businessId = (int)($_SESSION['business_id'] ?? 0);
    $roleId = (int)($_SESSION['role_id'] ?? 0);
    if ($businessId <= 0 || $roleId <= 0) return false;
    $sql = "SELECT rp.`{$field}` FROM role_permissions rp INNER JOIN permissions p ON p.id=rp.permission_id WHERE rp.business_id=? AND rp.role_id=? AND p.is_active=1 AND p.permission_code IN ('perm.staff.roles','perm.staff') ORDER BY FIELD(p.permission_code,'perm.staff.roles','perm.staff') LIMIT 1";
    $stmt = $conn->prepare($sql); if (!$stmt) return false;
    $stmt->bind_param('ii',$businessId,$roleId); $stmt->execute();
    $row = $stmt->get_result()->fetch_assoc(); $stmt->close();
    return (int)($row[$field] ?? 0) === 1;
}

if (!rolePagePermission($conn,'open')) { http_response_code(403); die('Access denied. You do not have permission to open roles.'); }
$canView = rolePagePermission($conn,'view') || rolePagePermission($conn,'open');
$canCreate = rolePagePermission($conn,'create');
$canUpdate = rolePagePermission($conn,'update');
$canDelete = rolePagePermission($conn,'delete');
$businessId = (int)($_SESSION['business_id'] ?? 0);
$isPlatformAdmin = (($_SESSION['user_type'] ?? '') === 'Platform Admin');
if ($businessId <= 0) { http_response_code(403); die('A valid business must be selected before managing roles.'); }
if (empty($_SESSION['roles_csrf'])) $_SESSION['roles_csrf'] = bin2hex(random_bytes(32));
$csrfToken = $_SESSION['roles_csrf'];

$theme = ['primary_color'=>'#d89416','primary_dark_color'=>'#b86a0b','primary_soft_color'=>'#fff6e5','sidebar_gradient_1'=>'#171c21','sidebar_gradient_2'=>'#20272d','sidebar_gradient_3'=>'#101419','page_background'=>'#f4f3f0','card_background'=>'#ffffff','text_color'=>'#171717','muted_text_color'=>'#7d8794','border_color'=>'#e8e8e8','font_family'=>'Inter','heading_font_family'=>'Playfair Display','border_radius_px'=>12,'sidebar_width_px'=>230];
$stmt=$conn->prepare('SELECT * FROM business_theme_settings WHERE business_id=? LIMIT 1');
if($stmt){$stmt->bind_param('i',$businessId);$stmt->execute();$row=$stmt->get_result()->fetch_assoc()?:[];$stmt->close();foreach($theme as $k=>$v){if(isset($row[$k])&&$row[$k]!==''&&$row[$k]!==null)$theme[$k]=$row[$k];}}

$roles=[];
$sql="SELECT r.*, COUNT(DISTINCT ur.user_id) AS user_count, COUNT(DISTINCT CASE WHEN rp.can_open=1 THEN rp.permission_id END) AS open_permission_count, COUNT(DISTINCT rp.permission_id) AS permission_count FROM roles r LEFT JOIN user_roles ur ON ur.role_id=r.id AND ur.business_id=? LEFT JOIN role_permissions rp ON rp.role_id=r.id AND rp.business_id=? WHERE (r.business_id=? OR r.business_id IS NULL) GROUP BY r.id ORDER BY r.is_system DESC,r.is_active DESC,r.role_name";
$stmt=$conn->prepare($sql);$stmt->bind_param('iii',$businessId,$businessId,$businessId);$stmt->execute();$res=$stmt->get_result();while($x=$res->fetch_assoc()){if(!$isPlatformAdmin && $x['role_code']==='PLATFORM_ADMIN')continue;$roles[]=$x;}$stmt->close();

$permissions=[];
$sql="SELECT p.id,p.permission_code,p.permission_name,p.description,p.menu_item_id,m.menu_title,m.menu_code,m.parent_id,m.sort_order,pm.menu_title AS parent_title FROM permissions p INNER JOIN menu_items m ON m.id=p.menu_item_id LEFT JOIN menu_items pm ON pm.id=m.parent_id WHERE p.is_active=1 AND m.is_active=1 AND m.is_visible=1 AND (p.business_id IS NULL OR p.business_id=?) ORDER BY COALESCE(pm.sort_order,m.sort_order),pm.sort_order,m.sort_order,p.permission_name";
$stmt=$conn->prepare($sql);$stmt->bind_param('i',$businessId);$stmt->execute();$res=$stmt->get_result();while($x=$res->fetch_assoc()){$permissions[]=$x;}$stmt->close();

$groups=[];foreach($permissions as $p){$g=$p['parent_title']?:$p['menu_title'];if(!isset($groups[$g]))$groups[$g]=[];$groups[$g][]=$p;}
$stats=['total'=>count($roles),'active'=>0,'system'=>0,'custom'=>0];foreach($roles as $r){if((int)$r['is_active']===1)$stats['active']++;if((int)$r['is_system']===1)$stats['system']++;else $stats['custom']++;}
$pageTitle='Roles & Permissions';$businessName=(string)($_SESSION['business_name']??'Jewellery ERP');
?>
