(--text-color);background:transparent}.role-title{display:flex;align-items:center;gap:10px;min-width:200px}.role-icon{width:34px;height:34px;border-radius:calc(var(--radius)*.65);display:flex;align-items:center;justify-content:center;background:var(--primary-soft);color:var(--primary-dark)}.role-name{font-weight:700}.small-muted{font-size:9px;color:var(--muted-color)}.badge-soft,.badge-status{display:inline-flex;align-items:center;border-radius:999px;padding:4px 8px;font-size:9px;font-weight:700}.badge-soft{background:var(--primary-soft);color:var(--primary-dark)}.badge-active{background:#eaf8f0;color:#168449}.badge-inactive{background:#fdecec;color:#bd2d2d}.action-btn{width:30px;height:30px;border:1px solid var(--border-color);border-radius:calc(var(--radius)*.65);background:var(--card-bg);color:var(--text-color);display:inline-flex;align-items:center;justify-content:center;font-size:10px}.action-btn:hover{background:var(--primary-soft);color:var(--primary-dark)}.action-btn.danger:hover{background:#fdecec;color:#bd2d2d}.modal-content{background:var(--card-bg);color:var(--text-color);border:1px solid var(--border-color);border-radius:var(--radius);overflow:hidden}.modal-header,.modal-footer{border-color:var(--border-color)}.modal-title{font-family:<?php echo json_encode((string)$theme['heading_font_family']); ?>,serif;font-size:16px;font-weight:700}.field-label{font-size:10px;font-weight:700;margin-bottom:5px;display:block}.permission-toolbar{display:flex;gap:8px;flex-wrap:wrap;align-items:center;margin-bottom:10px}.permission-wrap{border:1px solid var(--border-color);border-radius:var(--radius);overflow:hidden}.permission-group{border-bottom:1px solid var(--border-color)}.permission-group:last-child{border-bottom:0}.permission-group-head{padding:10px 12px;background:color-mix(in srgb,var(--card-bg) 94%,var(--muted-color));display:flex;align-items:center;justify-content:space-between;gap:10px}.permission-group-title{font-size:11px;font-weight:800}.permission-grid{di