<td class="role-column" data-label="Role"><div class="role-title"><div class="role-icon"><i class="fa-solid <?php echo (int)$role['is_system']===1?'fa-shield-halved':'fa-user-gear'; ?>"></i></div><div><div class="role-name"><?php echo e($role['role_name']); ?></div><div class="small-muted"><?php echo e($role['role_code']); ?><?php if($role['description']): ?> · <?php echo e($role['description']); ?><?php endif; ?></div></div></div></td>
