roup"><div class="permission-group-head"><div class="permission-group-title"><?php echo e($groupName); ?></div><div><button type="button" class="btn btn-light btn-sm grant-group">Grant group</button></div></div><?php foreach($items as $p): ?><div class="permission-grid permission-row" data-permission="<?php echo (int)$p['id']; ?>"><div class="perm-name"><strong><?php echo e($p['menu_title']); ?></strong><div class="small-muted"><?php echo e($p['permission_code']); ?></div></div><?php foreach(['can_open','can_view_value','can_view','can_create','can_update','can_approve','can_delete'] as $field): ?><div><input class="form-check-input perm-check" type="checkbox" name="permissions[<?php echo (int)$p['id']; ?>][<?php echo $field; ?>]" value="1" data-field="<?php echo $field; ?>"></div><?php endforeach; ?></div><?php endforeach; ?></div><?php endforeach; ?></div></div><div class="modal-footer"><button class="btn btn-light btn-sm" type="button" data-bs-dismiss="modal">Cancel</button><button class="btn-theme" id="saveRoleButton" type="submit"><i class="fa-solid fa-floppy-disk me-2"></i>Save Role</button></div></form></div></div>
