<script>
(function(){'use strict';var csrf=<?php echo json_encode($csrfToken); ?>,modalEl=document.getElementById('roleModal'),modal=modalEl?new bootstrap.Modal(modalEl):null,form=document.getElementById('roleForm');function toast(type,msg){var t=document.createElement('div');t.className='theme-toast theme-toast-'+type;t.innerHTML='<i class="fa-solid '+(type==='success'?'fa-circle-check':'fa-circle-exclamation')+'"></i><span></span>';t.querySelector('span').textContent=msg;document.body.appendChild(t);requestAnimationFrame(function(){t.classList.add('show')});setTimeout(function(){t.classList.remove('show');setTimeout(function(){t.remove()},250)},3200)}async function api(fd){var r=await fetch('api/roles-save.php',{method:'POST',body:fd,credentials:'same-origin',headers:{'X-Requested-With':'XMLHttpRequest'}}),j=await r.json().catch(function(){return{success:false,message:'Invalid server response.'}});if(!r.ok||!j.success)throw new Error(j.message||'Request failed.');return j}function reset(){form.reset();document.getElementById('role_id').value='0';document.getElementById('roleModalTitle').textContent='Add Role';document.getElementById('role_code').readOnly=false;document.querySelectorAll('.perm-check').forEach(function(x){x.checked=false})}var add=document.getElementById('addRoleButton');if(add)add.addEventListener('click',function(){reset();modal.show()});document.getElementById('grantAll').addEventListener('click',function(){document.querySelectorAll('.perm-check').forEach(function(x){x.checked=true})});document.getElementById('clearAll').addEventListener('click',function(){document.querySelectorAll('.perm-check').forEach(function(x){x.checked=false})});document.querySelectorAll('.grant-group').forEach(function(b){b.addEventListener('click',function(){b.closest('.permission-group').querySelectorAll('.perm-check').forEach(function(x){x.checked=true})})});document.querySelectorAll('[data-field="can_open"]').forEach(function(x){x.addEventListener('change',function(){if(!x.checked)x.closest('.permission-row').querySelectorAll('.perm-check').forEach(function(y){y.checked=false})})});document.querySelectorAll('.perm-check:not([data-field="can_open"])').forEach(function(x){x.addEventListener('change',function(){if(x.checked){var o=x.closest('.permission-row').querySelector('[data-field="can_open"]');if(o)o.checked=true}})});var search=document.getElementById('roleSearch'),status=document.getElementById('roleStatus');function filter(){var q=(search.value||'').toLowerCase(),s=status.value;document.querySelectorAll('#rolesTable tbody tr').forEach(function(r){r.style.display=(!q||r.dataset.search.indexOf(q)!==-1)&&(!s||r.dataset.status===s)?'':'none'})}search.addEventListener('input',filter);status.addEventListener('change',filter);document.addEventListener('click',async function(e){var edit=e.target.closest('.edit-role'),clone=e.target.closest('.clone-role'),del=e.target.closest('.delete-role');if(edit||clone){try{var fd=new FormData();fd.append('action','get');fd.append('csrf_token',csrf);fd.append('role_id',(edit||clone).dataset.id);var j=await api(fd);reset();document.getElementById('roleModalTitle').textContent=clone?'Clone Role':'Edit Role';document.getElementById('role_id').value=clone?'0':j.role.id;document.getElementById('role_code').value=clone?j.role.role_code+'_COPY':j.role.role_code;document.getElementById('role_name').value=clone?j.role.role_name+' Copy':j.role.role_name;document.getElementById('description').value=j.role.description||'';document.getElementById('is_active').value=String(j.role.is_active);if(!clone&&Number(j.role.is_system)===1)document.getElementById('role_code').readOnly=true;(j.permissions||[]).forEach(function(p){Object.keys(p).forEach(function(k){if(k==='permission_id')return;if(Number(p[k])===1){var c=document.querySelector('.permission-row[data-permission="'+p.permission_id+'"] [data-field="'+k+'"]');if(c)c.checked=true}})});modal.show()}catch(err){toast('error',err.message)}}if(del){if(!confirm('Delete '+del.dataset.name+'?'))return;var fd2=new FormData();fd2.append('action','delete');fd2.append('csrf_token',csrf);fd2.append('role_id',del.dataset.id);try{var j2=await api(fd2);toast('success',j2.message);del.closest('tr').remove()}catch(err2){toast('error',err2.message)}}});form.addEventListener('submit',async function(e){e.preventDefault();var b=document.getElementById('saveRoleButton'),old=b.innerHTML;b.disabled=true;b.innerHTML='<i class="fa-solid fa-spinner fa-spin me-2"></i>Saving...';try{var j=await api(new FormData(form));toast('success',j.message);modal.hide();setTimeout(function(){location.reload()},500)}catch(err){toast('error',err.message)}finally{b.disabled=false;b.innerHTML=old}})})();
</script></body></html>
